```cpp
#include <cstdio>

int main() {
    FILE* pipe = popen("command", "w");
    if (!pipe) {
        // Handle error
        return 1;
    }
    fprintf(pipe, "Hello, World!\n");
    pclose(pipe);
    return 0;
}
```

For more detailed control, you might want to use `fork`, `exec`, and `dup2`:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    pid_t pid = fork();
    if (pid < 0) {
        // Handle error
        return 1;
    } else if (pid == 0) { // Child process
        // Redirect stdin and stdout to the same file descriptor
        int fd[2];
        pipe(fd);
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[1], STDOUT_FILENO);

        // Close unused ends of the pipe
        close(fd[0]);
        close(fd[1]);

        // Execute the command
        execl("/bin/bash", "bash", "-c", "cat", (char*)0);
    } else { // Parent process
        // Wait for child to finish
        wait(NULL);
        return 0;
    }
}
```

